const items = $input.first().json.data || [];
if (items.length === 0) return [];
return items.map(item => ({ json: item }));

const lead = $('Split Leads').first().json;
const campaign = $input.first().json;

const systemPrompt = campaign.systemPrompt || `คุณเป็นผู้เชี่ยวชาญด้านการเขียน Cold Email ภาษาไทยสำหรับ B2B
เขียนอีเมลที่เป็นธรรมชาติ ไม่เป็นทางการจนเกินไป และตรงประเด็น
ห้ามใช้คำว่า "เรียน" หรือรูปแบบอีเมลทางการมากเกินไป
ความยาวไม่เกิน 150 คำ`;

const userPrompt = `เขียน Cold Email ให้กับบริษัท:
- ชื่อบริษัท: ${lead.companyName}
- ที่อยู่: ${lead.address || 'ไม่ระบุ'}
- เว็บไซต์: ${lead.website || 'ไม่มี'}
- อุตสาหกรรม: ${lead.industry || campaign.targetIndustry || 'ไม่ระบุ'}

แคมเปญ: ${campaign.name}
ผู้ส่ง: ${campaign.senderName} จาก BestSolutions Corp

ต้องการ JSON format:
{
  "subject": "หัวข้ออีเมล",
  "body_html": "เนื้อหาอีเมล HTML",
  "body_text": "เนื้อหาอีเมล plain text",
  "confidence": 0.85,
  "reasoning": "เหตุผลที่ให้คะแนนนี้"
}`;

return [{
  json: {
    lead,
    campaign,
    systemPrompt,
    userPrompt,
    campaignLeadId: lead.campaignLeads?.[0]?.id
  }
}];

const claudeResponse = $input.first().json;
const prevData = $('Build AI Prompt').first().json;

let emailData;
try {
  const content = claudeResponse.content?.[0]?.text || '';
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON found in Claude response');
  emailData = JSON.parse(jsonMatch[0]);
} catch(e) {
  emailData = {
    subject: `โซลูชันที่น่าสนใจสำหรับ ${prevData.lead.companyName}`,
    body_html: `<p>สวัสดีครับ/ค่ะ</p><p>ผมชื่อ ${prevData.campaign.senderName} จาก BestSolutions Corp ครับ</p>`,
    body_text: `สวัสดีครับ/ค่ะ`,
    confidence: 0.5,
    reasoning: 'Parse error - fallback used'
  };
}

const usage = claudeResponse.usage || {};
const tokensUsed = (usage.input_tokens || 0) + (usage.output_tokens || 0);
const costUsd = tokensUsed * 0.00000025;

return [{
  json: {
    ...prevData,
    subject: emailData.subject,
    bodyHtml: emailData.body_html,
    bodyText: emailData.body_text,
    confidence: emailData.confidence || 0.7,
    reasoning: emailData.reasoning,
    tokensUsed,
    costUsd
  }
}];

